<?php
namespace App\Domain\Equipment;use App\Domain\Equipment\Data\CharacterEquipmentStats;use App\Domain\Equipment\Data\ItemStatBonuses;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Models\Character;use App\Models\Item;use InvalidArgumentException;
final class CharacterEquipmentStatsProvider{private $items;public function __construct(EquippableItemValidator $items){$this->items=$items;}public function snapshot(Character $character){if(!$character->exists)return new CharacterEquipmentStats(new ItemStatBonuses(),[]);$rows=$character->equipment()->with('itemInstance')->orderBy('slot')->get();$ids=$rows->map(function($row){return$row->itemInstance?$row->itemInstance->item_id:null;})->filter()->unique()->values();$catalog=$ids->isEmpty()?collect():Item::whereIn('id',$ids)->get()->keyBy('id');$totals=['max_health'=>0,'attack'=>0,'defense'=>0,'accuracy'=>0,'evasion'=>0,'critical_chance'=>0.0,'attack_speed'=>0.0];$sources=[];foreach($rows as $row){$instance=$row->itemInstance;$item=$instance?$catalog->get($instance->item_id):null;if(!$instance||!$item||(int)$row->character_id!==(int)$character->id||(int)$instance->character_id!==(int)$character->id||$instance->status!==ItemInstanceStatus::EQUIPPED)throw new InvalidArgumentException('Inconsistent character equipment state.');$this->items->assertCompatible($item,$row->slot);$bonus=$this->items->bonuses($item);$values=$bonus->toArray();foreach(['max_health','attack','defense','accuracy','evasion'] as $key){if($values[$key]>PHP_INT_MAX-$totals[$key])throw new InvalidArgumentException('Equipment stat bonus overflow.');$totals[$key]+=$values[$key];}$totals['critical_chance']+=$bonus->criticalChance();$totals['attack_speed']+=$bonus->attackSpeed();if(!is_finite($totals['critical_chance'])||!is_finite($totals['attack_speed']))throw new InvalidArgumentException('Equipment decimal bonus overflow.');$sources[]=['slot'=>$row->slot,'item_instance_uuid'=>$instance->uuid,'item_id'=>(int)$item->id,'item_name'=>$item->name,'refinement_level'=>(int)$instance->refinement_level,'bonuses'=>$values];}return new CharacterEquipmentStats(new ItemStatBonuses($totals['max_health'],$totals['attack'],$totals['defense'],$totals['accuracy'],$totals['evasion'],$totals['critical_chance'],$totals['attack_speed']),$sources);}}
